/**
 * types/index.ts
 *
 * Shared TypeScript type definitions for the Whop Email Engine.
 *
 * Database-level types are generated by Prisma — import from @prisma/client.
 * This file holds application-layer types: API shapes, UI state, etc.
 */

// ---------------------------------------------------------------------------
// Generic API response wrapper
// Extended to include plan upgrade errors as a first-class response type.
// ---------------------------------------------------------------------------

export type ApiResponse<T> =
  | { success: true; data: T }
  | { success: false; error: string; code?: string }
  | {
      success: false;
      upgradeRequired: true;
      message: string;
      feature?: string;
      currentPlan: string;
      suggestedPlan: string;
      suggestedPlanPrice: number;
      currentUsage?: number;
      limit?: number | null;
    };

/** Type guard — narrows to the upgrade-required variant */
export function isUpgradeRequired(
  res: ApiResponse<unknown>
): res is Extract<ApiResponse<unknown>, { upgradeRequired: true }> {
  return !res.success && 'upgradeRequired' in res && res.upgradeRequired === true;
}

// ---------------------------------------------------------------------------
// Pagination
// ---------------------------------------------------------------------------

export interface PaginationParams {
  page: number;
  limit: number;
}

export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
  hasNextPage: boolean;
  hasPrevPage: boolean;
}

// ---------------------------------------------------------------------------
// Workspace / Tenant
// ---------------------------------------------------------------------------

export interface WorkspaceContext {
  workspaceId: string;
  userId: string;
  role: WorkspaceMemberRole;
}

export type WorkspaceMemberRole = "OWNER" | "ADMIN" | "MEMBER";

// ---------------------------------------------------------------------------
// Campaign status
// ---------------------------------------------------------------------------

export type CampaignStatus =
  | "DRAFT"
  | "SCHEDULED"
  | "SENDING"
  | "COMPLETED"
  | "FAILED"
  | "PAUSED";

// ---------------------------------------------------------------------------
// Email send status
// ---------------------------------------------------------------------------

export type EmailSendStatus =
  | "PENDING"
  | "SENT"
  | "DELIVERED"
  | "OPENED"
  | "CLICKED"
  | "BOUNCED"
  | "FAILED"
  | "UNSUBSCRIBED";

// ---------------------------------------------------------------------------
// Email provider
// ---------------------------------------------------------------------------

export type EmailProvider = "RESEND" | "SMTP";

// ---------------------------------------------------------------------------
// Contact
// ---------------------------------------------------------------------------

export interface ContactFilters {
  workspaceId: string;
  search?: string;
  tags?: string[];
  isSubscribed?: boolean;
  page?: number;
  limit?: number;
}

// ---------------------------------------------------------------------------
// Whop API types
// ---------------------------------------------------------------------------

export interface WhopMember {
  id: string;
  email: string;
  username?: string;
  name?: string;
  profilePicture?: string;
  createdAt: string;
}

export interface WhopProduct {
  id: string;
  name: string;
  createdAt: string;
}

// ---------------------------------------------------------------------------
// Sync
// ---------------------------------------------------------------------------

export type SyncStatus = "IDLE" | "RUNNING" | "SUCCESS" | "FAILED";

export interface SyncResult {
  status: SyncStatus;
  synced: number;
  skipped: number;
  errors: number;
  startedAt: Date;
  completedAt?: Date;
  errorDetails?: string[];
}
